import java.util.HashMap;
import java.util.Map;

public class Annagram {

    public static void main(String[] args) {
        String s = "";
        String t = "";

        Annagram a = new Annagram();
        System.out.println(a.isAnagram(s,t));
    }

    public boolean isAnagram(String s, String t) {

        if(s.length() != t.length()){
            return false;
        }

        Map<Character, Integer> hashMap = new HashMap<>();

        for(int i = 0; i< s.length() ; i++){
            char c = s.charAt(i);
            if(hashMap.containsKey(c)){
                hashMap.put(c, hashMap.get(c) + 1 );
            }else{
                hashMap.put(c, 1);
            }
        }

        Map<Character, Integer> hashMapT = new HashMap<>();

        for(int i = 0; i< t.length() ; i++){
            char c = t.charAt(i);
            if(hashMapT.containsKey(c)){
                hashMapT.put(c, hashMapT.get(c) + 1 );
            }else{
                hashMapT.put(c, 1);
            }
        }

        System.out.println(hashMapT);
        System.out.println(hashMap.keySet());

        for(char c  : hashMapT.keySet()){
            int i = hashMapT.get(c);
            int j = hashMap.get(c);

//            if( i != j){
//                return false;
//            }
            if(hashMapT.get(c) != hashMap.get(c)){
                return false;
            }

        }

        return true;
    }

}


